// KPress client icon helper. The glyphs live in the SVG sprite
// (static/icons/icons.svg), which the server inlines once per document. This only builds
// a `<use>` reference to a sprite symbol -- there is no SVG markup in JS. Icon-only: the
// visible label belongs in aria-label/title on the control, not here.

/**
 * Reference a sprite symbol by name (e.g. "copy", "check", "triangle-alert").
 * @param {string} name
 * @param {string} [className]
 * @returns {string}
 */
export function icon(name, className = "") {
  const cls = className ? ` class="${className}"` : "";
  return `<svg${cls} aria-hidden="true"><use href="#kpress-icon-${name}"></use></svg>`;
}

_kpress/assets/js/menu.js:
/**
 * Menu/popover behavior primitive (`kpress.menu`): the headless engine behind
 * the settings gear and any other segmented-chooser popover. Extracted from
 * the former theme.js `bindSettingsMenu` so widgets (built-in or host) compose
 * it instead of re-implementing open/close/dismiss/marking (see
 * kpress-design.md "Extension and Injection Model", layer B).
 */

/**
 * Wire a popover: toggle on the button, dismiss on outside click or Escape.
 * Visibility is driven by `aria-expanded` on the wrapper. Idempotent — a
 * second bind on the same wrapper returns null.
 *
 * @param {HTMLElement} wrap
 * @param {HTMLElement} button
 * @returns {(() => void) | null} disposer, or null when already bound
 */
export function bindMenu(wrap, button) {
  if (!wrap || !button || wrap.getAttribute("data-kpress-bound") === "true") {
    return null;
  }
  wrap.setAttribute("data-kpress-bound", "true");
  const isOpen = () => wrap.getAttribute("aria-expanded") === "true";
  /** @param {boolean} open */
  const setOpen = (open) => wrap.setAttribute("aria-expanded", open ? "true" : "false");
  /** @param {MouseEvent} event */
  const onButtonClick = (event) => {
    event.stopPropagation();
    setOpen(!isOpen());
  };
  /** @param {MouseEvent} event */
  const onDocumentClick = (event) => {
    if (isOpen() && !wrap.contains(/** @type {Node} */ (event.target))) {
      setOpen(false);
    }
  };
  /** @param {KeyboardEvent} event */
  const onKeydown = (event) => {
    if (event.key === "Escape" && isOpen()) {
      setOpen(false);
    }
  };
  button.addEventListener("click", onButtonClick);
  document.addEventListener("click", onDocumentClick);
  document.addEventListener("keydown", onKeydown);
  return () => {
    button.removeEventListener("click", onButtonClick);
    document.removeEventListener("click", onDocumentClick);
    document.removeEventListener("keydown", onKeydown);
    wrap.removeAttribute("data-kpress-bound");
  };
}

/**
 * Mark the active segment in a chooser group: `aria-checked="true"` on the
 * `[role="menuitemradio"]` child whose `data-*` value matches.
 *
 * @param {HTMLElement | Document} group
 * @param {string} dataKey camelCase dataset key, e.g. "kpressThemeChoice"
 * @param {string} value
 */
export function markChecked(group, dataKey, value) {
  for (const segment of group.querySelectorAll('[role="menuitemradio"]')) {
    const el = /** @type {HTMLElement} */ (segment);
    el.setAttribute("aria-checked", el.dataset[dataKey] === value ? "true" : "false");
  }
}

const kpressGlobal = /** @type {Record<string, unknown>} */ (
  /** @type {Record<string, unknown>} */ (globalThis).kpress ?? {}
);
/** @type {Record<string, unknown>} */ (globalThis).kpress = kpressGlobal;
kpressGlobal.menu = { bindMenu, markChecked };

_kpress/assets/js/overlay.js:
/**
 * Shared overlay/positioning primitive for KPress.
 *
 * Provides viewport-aware placement, dismiss handlers (Escape, resize,
 * outside-click), and backdrop management used by tooltips, video popovers,
 * and the table-of-contents drawer.
 *
 * Floating-UI reconsider tripwire: adopt Floating UI if and only if the
 * overlay system requires multi-axis collision detection with simultaneous
 * flip + shift, OR virtual element anchoring for non-DOM triggers. Until
 * then, the cost of a JS runtime dependency is not justified.
 */

import { addViewportResizeListener, resolveKpressViewport } from "./viewport.js";

export const OVERLAY_VIEWPORT_MARGIN_PX = 10;
export const OVERLAY_DEFAULT_GAP_PX = 10;

/**
 * @typedef {{ top: number; bottom: number; left: number; right: number; width: number; height: number }} TriggerRect
 * @typedef {{ width: number; height: number }} OverlaySize
 * @typedef {{
 *   viewportWidth: number;
 *   viewportHeight: number;
 *   preferred?: "top" | "bottom" | "left" | "right";
 *   gap?: number;
 *   margin?: number;
 * }} PositionOptions
 * @typedef {{ side: "top" | "bottom" | "left" | "right"; top: number; left: number }} PositionResult
 */

/**
 * Compute viewport-aware position for an overlay element relative to a trigger.
 *
 * Attempts the preferred side, flipping to the opposite if there is not enough
 * room. Clamps the cross-axis so the overlay stays within viewport margins.
 *
 * @param {TriggerRect} trigger - bounding rect of the trigger element
 * @param {OverlaySize} overlay - measured width/height of the overlay
 * @param {PositionOptions} options
 * @returns {PositionResult}
 */
export function computePosition(trigger, overlay, options) {
  const preferred = options.preferred ?? "bottom";
  const gap = options.gap ?? OVERLAY_DEFAULT_GAP_PX;
  const margin = options.margin ?? OVERLAY_VIEWPORT_MARGIN_PX;
  const vw = options.viewportWidth;
  const vh = options.viewportHeight;

  /** @param {number} value @param {number} min @param {number} max */
  const clamp = (value, min, max) => Math.max(min, Math.min(max, value));

  if (preferred === "right" || preferred === "left") {
    const fitsRight = trigger.right + gap + overlay.width + margin <= vw;
    const fitsLeft = trigger.left - gap - overlay.width >= margin;
    const side =
      preferred === "right"
        ? fitsRight
          ? "right"
          : fitsLeft
            ? "left"
            : "right"
        : fitsLeft
          ? "left"
          : fitsRight
            ? "right"
            : "left";

    const left =
      side === "right"
        ? Math.min(trigger.right + gap, vw - overlay.width - margin)
        : Math.max(margin, trigger.left - gap - overlay.width);

    const centerY = trigger.top + trigger.height / 2 - overlay.height / 2;
    const top = clamp(centerY, margin, vh - overlay.height - margin);

    return { side, top, left };
  }

  const fitsBottom = trigger.bottom + gap + overlay.height + margin <= vh;
  const fitsTop = trigger.top - gap - overlay.height >= margin;
  const side =
    preferred === "bottom"
      ? fitsBottom
        ? "bottom"
        : fitsTop
          ? "top"
          : "bottom"
      : fitsTop
        ? "top"
        : fitsBottom
          ? "bottom"
          : "top";

  const top =
    side === "bottom" ? trigger.bottom + gap : Math.max(margin, trigger.top - gap - overlay.height);

  const centerX = trigger.left + trigger.width / 2 - overlay.width / 2;
  const left = clamp(centerX, margin, vw - overlay.width - margin);

  return { side, top, left };
}

/**
 * Register an Escape-key dismiss handler on the document.
 *
 * @param {() => void} callback
 * @returns {() => void} cleanup function to remove the listener
 */
export function dismissOnEscape(callback) {
  /** @param {KeyboardEvent} event */
  const handler = (event) => {
    if (event.key === "Escape") {
      callback();
    }
  };
  document.addEventListener("keydown", handler);
  return () => document.removeEventListener("keydown", handler);
}

/**
 * Register a viewport resize dismiss handler.
 *
 * @param {() => void} callback
 * @param {Document | Element | null | undefined} [viewport]
 * @returns {() => void} cleanup function to remove the listener
 */
export function dismissOnResize(callback, viewport = document) {
  return addViewportResizeListener(resolveKpressViewport(viewport), callback);
}

/**
 * Register a click-outside dismiss handler for an overlay element.
 *
 * @param {Element | null} overlay
 * @param {() => void} callback
 * @returns {() => void} cleanup function to remove the listener
 */
export function dismissOnOutsideClick(overlay, callback) {
  /** @param {MouseEvent} event */
  const handler = (event) => {
    if (!overlay || !(event.target instanceof Node)) {
      return;
    }
    if (!overlay.contains(event.target)) {
      callback();
    }
  };
  document.addEventListener("click", handler);
  return () => document.removeEventListener("click", handler);
}

/**
 * Toggle a backdrop element's visibility.
 *
 * @param {Element | null} backdrop
 * @param {boolean} visible
 */
export function toggleBackdrop(backdrop, visible) {
  if (!backdrop) {
    return;
  }
  backdrop.classList.toggle("kpress-visible", visible);
  backdrop.setAttribute("aria-hidden", String(!visible));
}

_kpress/assets/js/runtime.js:
/**
 * KPress client runtime: the host-facing JS surface and the seam KPress's own
 * built-ins use (the dogfood rule — see kpress-design.md "Extension and
 * Injection Model"). It assembles the `kpress` global from small parts:
 *
 * - `model()` — the parsed #kpress-page-model page model (layer A).
 * - `on`/`off`/`emit` — events (`kpress:ready`, `widget:change`, ...).
 * - `storage` — persistence with a pluggable adapter (localStorage default;
 *   an embedding host can swap in cookies with one call).
 * - `widgets` — client-rendered chrome: register/configure/mount over the
 *   server-emitted `[data-kpress-widget]` mounts (no-JS rule).
 * - `behaviors` — bindings over server-rendered markup: register/override/
 *   configure/rebind.
 *
 * Lifecycle: modules register at import (no DOM work); the runtime applies all
 * registrations once the document is ready and emits `kpress:ready`. Host
 * scripts loaded earlier (head_extra_html) therefore register/override before
 * built-ins are applied; anything registered after ready is applied
 * immediately. Other KPress modules attach their own namespaces (e.g.
 * `kpress.theme`, `kpress.menu`) — assembled, not monolithic.
 *
 * Fault isolation: one registration (widget mount, behavior bind, event
 * listener, storage adapter) failing must not take down the rest of the page
 * or suppress `kpress:ready` — failures are reported via `console.error` and
 * the pass continues.
 */

/** @typedef {{ get(key: string): string | null, set(key: string, value: string): void }} KpressStorageAdapter */
/** @typedef {(detail?: unknown) => void} KpressListener */
/** @typedef {Record<string, unknown>} KpressConfig */
/** @typedef {{ mount(el: HTMLElement, config: KpressConfig, model: KpressConfig): void }} KpressWidget */
/**
 * A behavior binds handling over server-rendered markup. `bind` MAY return a
 * disposer that tears the binding down (listeners, observers); the runtime
 * stores it per behavior id and calls it before re-binding the id
 * (`override`, `rebind`, or a re-`register`), so replacement is real — no
 * built-in wiring lingers behind a host override.
 *
 * @typedef {{ bind(root: Document | HTMLElement, config: KpressConfig): (() => void) | void }} KpressBehavior
 */

/** @type {KpressConfig | null} */
let cachedModel = null;

/**
 * The page model published by the server (#kpress-page-model), parsed once.
 * Fragments have no block; embeds get the same data in the render payload.
 *
 * @returns {KpressConfig}
 */
export function getModel() {
  if (cachedModel === null) {
    /** @type {KpressConfig} */
    let parsed = {};
    // Match the <script> element specifically: content-authored HTML can carry an
    // id (e.g. <div id="kpress-page-model">) under the sanitizing trust modes, and
    // getElementById would return that clobbering element if it precedes ours. A
    // <script> tag from content is always stripped by the sanitizer, so this selector
    // can only match the server-emitted page model.
    const block = document.querySelector("script#kpress-page-model");
    if (block?.textContent) {
      try {
        parsed = JSON.parse(block.textContent) ?? {};
      } catch {
        parsed = {};
      }
    }
    if (typeof parsed.widgets !== "object" || parsed.widgets === null) {
      parsed.widgets = {};
    }
    cachedModel = parsed;
  }
  return cachedModel;
}

/** @type {Map<string, Set<KpressListener>>} */
const listeners = new Map();

/**
 * @param {string} type
 * @param {KpressListener} listener
 */
export function on(type, listener) {
  let set = listeners.get(type);
  if (!set) {
    set = new Set();
    listeners.set(type, set);
  }
  set.add(listener);
}

/**
 * @param {string} type
 * @param {KpressListener} listener
 */
export function off(type, listener) {
  listeners.get(type)?.delete(listener);
}

/**
 * @param {string} type
 * @param {unknown} [detail]
 */
export function emit(type, detail) {
  for (const listener of [...(listeners.get(type) ?? [])]) {
    try {
      listener(detail);
    } catch (error) {
      console.error(`kpress: "${type}" listener failed`, error);
    }
  }
}

/** @type {KpressStorageAdapter} */
const localStorageAdapter = {
  get(key) {
    try {
      return localStorage.getItem(key);
    } catch {
      return null;
    }
  },
  set(key, value) {
    try {
      localStorage.setItem(key, value);
    } catch {
      // Storage may be unavailable (private mode, sandboxed embed).
    }
  },
};

/** @type {KpressStorageAdapter} */
let activeAdapter = localStorageAdapter;

export const storage = {
  /**
   * A throwing custom adapter degrades to "nothing persisted" (null) rather
   * than breaking the caller (theme engine, widgets).
   *
   * @param {string} key
   */
  get(key) {
    try {
      return activeAdapter.get(key);
    } catch (error) {
      console.error("kpress: storage adapter get failed", error);
      return null;
    }
  },
  /**
   * A throwing custom adapter degrades to a no-op set.
   *
   * @param {string} key
   * @param {string} value
   */
  set(key, value) {
    try {
      activeAdapter.set(key, value);
    } catch (error) {
      console.error("kpress: storage adapter set failed", error);
    }
  },
  /**
   * Swap the persistence adapter (e.g. cookies for cross-port sharing).
   * Every primitive and widget persists through it from then on.
   *
   * @param {KpressStorageAdapter} adapter
   */
  use(adapter) {
    activeAdapter = adapter;
  },
};

let applied = false;

/** @type {Map<string, KpressWidget>} */
const widgetRegistry = new Map();
/** @type {Map<string, KpressConfig>} */
const widgetConfigs = new Map();

/**
 * Widget config: the page model's (opaque, verbatim) config under any
 * `configure()` values — the widget's own JS owns the schema.
 *
 * @param {string} id
 * @returns {KpressConfig}
 */
function resolveWidgetConfig(id) {
  const widgetsModel = /** @type {Record<string, unknown>} */ (getModel().widgets);
  const fromModel = widgetsModel?.[id];
  const base =
    fromModel && typeof fromModel === "object" ? /** @type {KpressConfig} */ (fromModel) : {};
  return { ...base, ...(widgetConfigs.get(id) ?? {}) };
}

/** @param {string} id */
function mountAllFor(id) {
  for (const el of document.querySelectorAll(`[data-kpress-widget="${id}"]`)) {
    if (el.getAttribute("data-kpress-widget-bound") === "true") {
      continue;
    }
    widgets.mount(id, /** @type {HTMLElement} */ (el));
  }
}

export const widgets = {
  /**
   * @param {string} id
   * @param {KpressWidget} widget
   */
  register(id, widget) {
    widgetRegistry.set(id, widget);
    if (applied) {
      mountAllFor(id);
    }
  },
  /**
   * Merge host config over the page model's for this widget id. Unknown ids
   * (typos) warn and store nothing.
   *
   * @param {string} id
   * @param {KpressConfig} config
   */
  configure(id, config) {
    if (!widgetRegistry.has(id)) {
      console.warn(
        `kpress: widgets.configure("${id}") ignored — no widget registered with that id`,
      );
      return;
    }
    widgetConfigs.set(id, { ...(widgetConfigs.get(id) ?? {}), ...config });
  },
  /**
   * Mount a registered widget into an element (embeds mount anywhere). The
   * element is marked bound so the ready pass never mounts a server mount a
   * second time after an explicit pre-ready mount. A throwing widget is
   * isolated (console.error) so one bad mount cannot abort the ready pass.
   *
   * @param {string} id
   * @param {HTMLElement} el
   * @param {KpressConfig} [config]
   */
  mount(id, el, config) {
    const widget = widgetRegistry.get(id);
    if (!widget) {
      console.warn(`kpress: widgets.mount("${id}") ignored — no widget registered with that id`);
      return;
    }
    if (!el) {
      return;
    }
    el.setAttribute("data-kpress-widget-bound", "true");
    try {
      widget.mount(el, config ?? resolveWidgetConfig(id), getModel());
    } catch (error) {
      console.error(`kpress: widget "${id}" mount failed`, error);
    }
  },
};

/** @type {Map<string, KpressBehavior>} */
const behaviorRegistry = new Map();
/** @type {Map<string, KpressConfig>} */
const behaviorConfigs = new Map();
/** Disposers returned by behavior binds, keyed by behavior id. @type {Map<string, () => void>} */
const behaviorDisposers = new Map();

/**
 * Run a behavior id's stored disposer (if any). Disposal failures are
 * isolated: re-binding proceeds regardless.
 *
 * @param {string} id
 */
function disposeBehavior(id) {
  const dispose = behaviorDisposers.get(id);
  if (!dispose) {
    return;
  }
  behaviorDisposers.delete(id);
  try {
    dispose();
  } catch (error) {
    console.error(`kpress: behavior "${id}" disposer failed`, error);
  }
}

/**
 * Dispose the id's previous binding, then bind. A throwing bind is isolated
 * (console.error) so one bad behavior cannot leave later behaviors unbound or
 * suppress `kpress:ready`.
 *
 * @param {string} id
 */
function runBehavior(id) {
  const behavior = behaviorRegistry.get(id);
  if (!behavior?.bind) {
    return;
  }
  disposeBehavior(id);
  try {
    const dispose = behavior.bind(document, behaviorConfigs.get(id) ?? {});
    if (typeof dispose === "function") {
      behaviorDisposers.set(id, dispose);
    }
  } catch (error) {
    console.error(`kpress: behavior "${id}" bind failed`, error);
  }
}

export const behaviors = {
  /**
   * @param {string} id
   * @param {KpressBehavior} behavior
   */
  register(id, behavior) {
    behaviorRegistry.set(id, behavior);
    if (applied) {
      runBehavior(id);
    }
  },
  /**
